import{bQ as d,aL as a,u as r,G as l}from"./chunks/framework.D06dwy5q.js";const i="/kb/assets/01-specific-problem-first.BHfd74-5.png",e="/kb/assets/02-simple-first.DdlY85B7.png",o="/kb/assets/03-ecosystem-maintenance.ChHdpIXq.png",n="/kb/assets/04-debug-exit-checklist.D0JSe54_.png",m=JSON.parse('{"title":"第 16 讲｜选型常识","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/16-选型常识.md","filePath":"00.互联网与架构基础/16-选型常识.md","lastUpdated":null}'),s={name:"00.互联网与架构基础/16-选型常识.md"};function h(u,t,p,b,q,c){return a(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="第-16-讲-选型常识" tabindex="-1">第 16 讲｜选型常识 <a class="header-anchor" href="#第-16-讲-选型常识" aria-label="Permalink to &quot;第 16 讲｜选型常识&quot;">​</a></h1><p>技术选型这件事,<strong>最容易被关注的是组件名字、性能跑分、流行趋势</strong>——这是网络上讨论最多、最容易搜到的内容。但系统真正运行起来后,选型对错的关键不在这些,而在更&quot;无聊&quot;的问题上:</p><ul><li>团队能不能维护</li><li>出故障时能不能查</li><li>数据能不能恢复</li><li>版本能不能升级</li></ul><p>一个组件进入系统,跟着进来的是<strong>一整套长期工作</strong>——部署、监控、备份、权限管理、版本升级、安全漏洞修复、故障处理流程、交接文档。<strong>选型不只是看组件能做什么,更要看它会给系统增加哪些长期负担</strong>。</p><p>本讲是整个&quot;互联网与架构基础&quot;系列的收尾,讨论选型的核心原则:问题定位、简单方案优先、稳定性与生态、团队维护能力、排查入口、退出路径——以及如何把这些原则应用到实际选型决策中。</p><h2 id="一、问题定位-问题不具体-方案就发散" tabindex="-1">一、问题定位:问题不具体,方案就发散 <a class="header-anchor" href="#一、问题定位-问题不具体-方案就发散" aria-label="Permalink to &quot;一、问题定位:问题不具体,方案就发散&quot;">​</a></h2><p>选型最忌讳的就是<strong>笼统的提问</strong>:</p><p><img src="'+i+`" alt="问题越具体，技术方案越容易收敛"></p><blockquote><p>&quot;系统性能不好,我们要不要上某某中间件?&quot;</p></blockquote><p><strong>问题不说具体,方案就没法收住</strong>——缓存、队列、分库分表、扩容、加机器、上微服务,所有方案都会被拉进来讨论。</p><h3 id="不同问题对应不同工具" tabindex="-1">不同问题对应不同工具 <a class="header-anchor" href="#不同问题对应不同工具" aria-label="Permalink to &quot;不同问题对应不同工具&quot;">​</a></h3><table tabindex="0"><thead><tr><th>现象</th><th>该先看哪里</th></tr></thead><tbody><tr><td>单个接口慢</td><td>SQL 优化、索引、下游接口、线程池</td></tr><tr><td>同一数据反复查</td><td>缓存(Redis)、接口缓存、CDN</td></tr><tr><td>后台任务耗时长</td><td>异步化、消息队列、任务调度系统</td></tr><tr><td>文件要多实例共享</td><td>对象存储、共享文件系统</td></tr><tr><td>服务实例经常变化</td><td>服务发现、负载均衡</td></tr><tr><td>发布经常出错</td><td>CI/CD 流水线、镜像管理、发布记录</td></tr><tr><td>出故障不知道在哪</td><td>指标、日志、链路追踪</td></tr><tr><td>数据库连接池满</td><td>连接池调优、慢查询优化、读写分离</td></tr><tr><td>高并发写入瓶颈</td><td>异步化、消息队列、分库分表</td></tr></tbody></table><h3 id="一个具体例子" tabindex="-1">一个具体例子 <a class="header-anchor" href="#一个具体例子" aria-label="Permalink to &quot;一个具体例子&quot;">​</a></h3><p>&quot;某接口慢&quot; 的合理排查路径:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第 1 步:看是哪条 SQL 慢?</span></span>
<span class="line"><span>  → EXPLAIN 看执行计划</span></span>
<span class="line"><span>  → 看 slow log 中的 Query_time、Rows_examined</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第 2 步:能否加索引?</span></span>
<span class="line"><span>  → 看到 Rows_examined=8000000,基本是缺索引</span></span>
<span class="line"><span>  → 加合适的联合索引</span></span>
<span class="line"><span></span></span>
<span class="line"><span>加索引后:接口从 5 秒降到 50ms 完成 ✓</span></span></code></pre></div><p><strong>这种优化成本极低、效果立竿见影</strong>——根本不需要分库分表这种大动作。</p><p>如果跳过排查直接上&quot;分库分表&quot;,改造成本巨大、运维复杂度暴涨,而问题可能根本就没解决。</p><h3 id="问题越具体-方案越容易收敛" tabindex="-1">问题越具体,方案越容易收敛 <a class="header-anchor" href="#问题越具体-方案越容易收敛" aria-label="Permalink to &quot;问题越具体,方案越容易收敛&quot;">​</a></h3><table tabindex="0"><thead><tr><th>表述</th><th>收敛程度</th></tr></thead><tbody><tr><td>&quot;系统性能不好&quot;</td><td>所有方案都会被拉进来</td></tr><tr><td>&quot;接口 P99 延迟从 200ms 涨到 2s&quot;</td><td>排查方向收窄到延迟相关</td></tr><tr><td>&quot;POST /api/orders 在 14:00 后 P99 从 200ms 涨到 2s&quot;</td><td>几乎能精确定位</td></tr><tr><td>&quot;slow log 显示 INSERT 时 lock wait 时间长&quot;</td><td>明确是锁等待问题</td></tr></tbody></table><p>把问题描述清楚是选型的第一步——<strong>不要为不存在的问题选方案</strong>。</p><h2 id="二、简单方案优先" tabindex="-1">二、简单方案优先 <a class="header-anchor" href="#二、简单方案优先" aria-label="Permalink to &quot;二、简单方案优先&quot;">​</a></h2><p>简单方案不是&quot;功能少&quot;,而是<strong>链路短、状态清楚、团队能接住</strong>:</p><p><img src="`+e+'" alt="复杂方案应该被真实问题推出来"></p><table tabindex="0"><thead><tr><th>简单方案的特点</th><th>具体表现</th></tr></thead><tbody><tr><td>链路短</td><td>请求经过的组件少,出问题排查范围小</td></tr><tr><td>状态清楚</td><td>数据存在哪里、谁在写谁在读,都能说清楚</td></tr><tr><td>恢复直接</td><td>出故障有明确的回滚和恢复方式</td></tr><tr><td>文档可接手</td><td>新同事通过文档、日志、配置能理解系统</td></tr></tbody></table><h3 id="过早引入复杂方案的坑" tabindex="-1">过早引入复杂方案的坑 <a class="header-anchor" href="#过早引入复杂方案的坑" aria-label="Permalink to &quot;过早引入复杂方案的坑&quot;">​</a></h3><p>很多团队踩过的坑就是<strong>为不存在的问题引入复杂方案</strong>:</p><table tabindex="0"><thead><tr><th>提前引入</th><th>没有真实问题时的代价</th></tr></thead><tbody><tr><td>读写分离</td><td>SQL 路由复杂度、复制延迟监控、切换流程</td></tr><tr><td>分库分表</td><td>路由层、跨片查询限制、扩容代价</td></tr><tr><td>微服务拆分(团队 5 人)</td><td>多服务部署、链路追踪、跨服务事务</td></tr><tr><td>Kubernetes(机器 &lt; 5 台)</td><td>学习成本、运维门槛、配置复杂度</td></tr><tr><td>服务网格(服务 &lt; 20 个)</td><td>Sidecar 资源、性能损耗、调试复杂</td></tr><tr><td>消息队列(并发 &lt; 100)</td><td>队列积压、消费失败、运维成本</td></tr><tr><td>分布式事务框架(单库可解决的事)</td><td>工程复杂度、性能损耗</td></tr></tbody></table><p><strong>这些方案在没有对应问题时,只留下纯粹的负担,没有任何收益</strong>。</p><h3 id="能用就别复杂" tabindex="-1">&quot;能用就别复杂&quot; <a class="header-anchor" href="#能用就别复杂" aria-label="Permalink to &quot;&quot;能用就别复杂&quot;&quot;">​</a></h3><p>一个判断原则:<strong>能用更简单方式解决的,就用更简单方式</strong>。</p><table tabindex="0"><thead><tr><th>需求</th><th>最简方案</th><th>过度方案</th></tr></thead><tbody><tr><td>每天凌晨备份</td><td>crontab 定时脚本</td><td>Argo Workflows + Job 调度系统</td></tr><tr><td>内部 100 人用的小工具</td><td>Nginx + 单进程 Python</td><td>Kubernetes + 微服务 + 服务网格</td></tr><tr><td>异步任务每天几百个</td><td>数据库 + 后台 worker 轮询</td><td>Kafka + Flink</td></tr><tr><td>缓存少量配置</td><td>进程内内存 map</td><td>Redis 集群 + 双写一致性</td></tr><tr><td>单机日志查看</td><td>grep + tail</td><td>ELK 全套</td></tr></tbody></table><p><strong>简单方案的价值会在长期凸显</strong>——更少的组件意味着更少的故障可能、更短的排查链路、更低的运维成本、更容易交接。</p><h3 id="复杂方案要被问题-推-出来" tabindex="-1">复杂方案要被问题&quot;推&quot;出来 <a class="header-anchor" href="#复杂方案要被问题-推-出来" aria-label="Permalink to &quot;复杂方案要被问题&quot;推&quot;出来&quot;">​</a></h3><p><strong>复杂方案有它的价值,但要被真实问题推出来,不是被流行趋势推出来</strong>。</p><p>合理引入复杂方案的判断:</p><ul><li>有具体的、可量化的痛点(P99 延迟 5 秒、数据库 CPU 持续 90%、单表 5 亿行)</li><li>简单方案已经做完(加索引、优化 SQL、加缓存)还不够</li><li>团队有能力运维复杂方案</li><li>引入后能带来明确收益</li></ul><p>满足以上才考虑上,不要为了&quot;看起来现代化&quot;提前引入。</p><h2 id="三、稳定性与生态-基础组件的核心考量" tabindex="-1">三、稳定性与生态:基础组件的核心考量 <a class="header-anchor" href="#三、稳定性与生态-基础组件的核心考量" aria-label="Permalink to &quot;三、稳定性与生态:基础组件的核心考量&quot;">​</a></h2><p>数据库、消息队列、网关、监控这种基础组件,<strong>一旦进入核心链路,替换成本极高</strong>(基本等于重写半个系统)。所以选这类组件时,<strong>稳定性、社区活跃度、文档质量、运维工具完备性,远比新特性更重要</strong>。</p><p><img src="'+o+'" alt="基础组件选型要看稳定性生态和维护活跃度"></p><h3 id="基础组件选型的观察点" tabindex="-1">基础组件选型的观察点 <a class="header-anchor" href="#基础组件选型的观察点" aria-label="Permalink to &quot;基础组件选型的观察点&quot;">​</a></h3><table tabindex="0"><thead><tr><th>观察点</th><th>具体看什么</th></tr></thead><tbody><tr><td>维护状态</td><td>社区或厂商是否持续修 bug、发安全补丁、出新版本</td></tr><tr><td>文档资料</td><td>出问题时能否查到资料、案例、踩坑经验</td></tr><tr><td>版本节奏</td><td>升级是否频繁破坏兼容性</td></tr><tr><td>生态适配</td><td>能否接入现有的认证、监控、部署流程</td></tr><tr><td>运维工具</td><td>备份、恢复、迁移、诊断工具是否成熟</td></tr><tr><td>招聘市场</td><td>能否招到有该组件经验的人</td></tr><tr><td>大规模生产案例</td><td>是否有同行已在生产稳定运行</td></tr><tr><td>安全审计历史</td><td>历史漏洞修复响应速度</td></tr></tbody></table><h3 id="小众组件的风险" tabindex="-1">小众组件的风险 <a class="header-anchor" href="#小众组件的风险" aria-label="Permalink to &quot;小众组件的风险&quot;">​</a></h3><p><strong>小众组件不是不能用</strong>,问题在于:</p><ul><li>核心链路出故障时,资料少</li><li>案例少,踩坑经验难找</li><li>社区响应慢</li><li>团队里没人熟,排查靠猜</li><li>招聘困难,知识传承难</li></ul><p>这些问题叠加起来,故障恢复时间会被严重拉长。<strong>凌晨三点的生产事故,任何人都不希望此时在 Google 一个完全陌生组件的报错信息</strong>。</p><h3 id="看似无聊但极重要的-维护活跃度" tabindex="-1">看似无聊但极重要的&quot;维护活跃度&quot; <a class="header-anchor" href="#看似无聊但极重要的-维护活跃度" aria-label="Permalink to &quot;看似无聊但极重要的&quot;维护活跃度&quot;&quot;">​</a></h3><p>GitHub 上的项目要看:</p><ul><li>最近一次 commit</li><li>最近的 release</li><li>Issues 中 maintainer 的活跃度</li><li>大版本的兼容性变更幅度</li></ul><p>某项目最近一年没有新 release、issues 大量未回复、最后一次安全更新是两年前——<strong>即使技术上看起来不错,也不能进生产</strong>。一个安全漏洞被披露后,没有维护者来修补丁,业务就只能裸奔。</p><h2 id="四、团队维护能力-语言与框架的现实考量" tabindex="-1">四、团队维护能力:语言与框架的现实考量 <a class="header-anchor" href="#四、团队维护能力-语言与框架的现实考量" aria-label="Permalink to &quot;四、团队维护能力:语言与框架的现实考量&quot;">​</a></h2><p><strong>语言和框架的选择不能脱离团队背景</strong>。</p><table tabindex="0"><thead><tr><th>团队背景</th><th>自然的技术栈</th></tr></thead><tbody><tr><td>长期维护 Java 微服务</td><td>Spring Boot + Spring Cloud,生态对接最容易</td></tr><tr><td>主要写 Python</td><td>FastAPI、Django,内部工具开发快</td></tr><tr><td>云原生工具开发</td><td>Go,部署形态简单(单二进制),性能高</td></tr><tr><td>与前端共用 JS</td><td>Node.js,前端能顺手写后端</td></tr><tr><td>C# / .NET 背景</td><td>ASP.NET Core,生态成熟</td></tr></tbody></table><h3 id="选型的真实考量维度" tabindex="-1">选型的真实考量维度 <a class="header-anchor" href="#选型的真实考量维度" aria-label="Permalink to &quot;选型的真实考量维度&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>要检查什么</th></tr></thead><tbody><tr><td>开发效率</td><td>写一个功能要多久</td></tr><tr><td>运行方式</td><td>部署、配置、日志、进程管理</td></tr><tr><td>性能要求</td><td>真实瓶颈是不是卡在语言运行时上</td></tr><tr><td>人员储备</td><td>团队能排查这种栈的线上问题吗</td></tr><tr><td>生态依赖</td><td>数据库驱动、认证集成、监控客户端、测试工具</td></tr><tr><td>招聘市场</td><td>新成员上手成本</td></tr></tbody></table><h3 id="能做-不等于-适合" tabindex="-1">&quot;能做&quot;不等于&quot;适合&quot; <a class="header-anchor" href="#能做-不等于-适合" aria-label="Permalink to &quot;&quot;能做&quot;不等于&quot;适合&quot;&quot;">​</a></h3><p><strong>一门语言&quot;能做很多事&quot;,不代表每个团队都适合用</strong>。</p><p>线上故障时需要回答的问题:</p><ul><li>框架内部异常怎么读?</li><li>连接池为什么耗尽?</li><li>协程/线程为什么阻塞?</li><li>GC 为什么抖动?</li><li>依赖版本为什么冲突?</li><li>内存为什么持续上涨?</li></ul><p>这些都需要<strong>有人能看得懂</strong>。没有这种人的时候强行上新技术栈,平时看起来很美好,出事时只能干瞪眼。</p><h3 id="性能-通常不是首要选型理由" tabindex="-1">&quot;性能&quot;通常不是首要选型理由 <a class="header-anchor" href="#性能-通常不是首要选型理由" aria-label="Permalink to &quot;&quot;性能&quot;通常不是首要选型理由&quot;">​</a></h3><p>新人选型时常拿性能跑分作为依据——但<strong>实际业务中,语言运行时的性能差距很少是真正的瓶颈</strong>。</p><table tabindex="0"><thead><tr><th>瓶颈类型</th><th>真实占比</th></tr></thead><tbody><tr><td>数据库慢查询</td><td>极高</td></tr><tr><td>外部 API 调用</td><td>高</td></tr><tr><td>网络延迟</td><td>中</td></tr><tr><td>日志/IO</td><td>中</td></tr><tr><td>GC / 内存管理</td><td>低</td></tr><tr><td>语言运行时计算</td><td>极低</td></tr></tbody></table><p>绝大多数 Web 业务,<strong>慢的是数据库、是外部调用、是阻塞 IO,不是语言本身</strong>。换语言不会让慢 SQL 变快,但换团队不熟悉的语言会让排查变难。</p><p>只有在极少数场景(实时计算、高频交易、大规模并发处理),语言运行时性能才成为决定性因素。普通业务<strong>应当按&quot;团队最熟悉&quot;选型</strong>,而非&quot;性能最好&quot;。</p><h2 id="五、排查入口-任何组件进生产前必须有" tabindex="-1">五、排查入口:任何组件进生产前必须有 <a class="header-anchor" href="#五、排查入口-任何组件进生产前必须有" aria-label="Permalink to &quot;五、排查入口:任何组件进生产前必须有&quot;">​</a></h2><p>任何组件进入生产环境之前,要先回答一个问题:<strong>它出问题的时候,从哪里看?</strong></p><p><img src="'+n+'" alt="组件进生产前要有排查入口和退出路径"></p><h3 id="各组件的最低排查入口要求" tabindex="-1">各组件的最低排查入口要求 <a class="header-anchor" href="#各组件的最低排查入口要求" aria-label="Permalink to &quot;各组件的最低排查入口要求&quot;">​</a></h3><table tabindex="0"><thead><tr><th>组件</th><th>至少要有的排查入口</th></tr></thead><tbody><tr><td>Nginx</td><td>access log、error log、upstream 状态</td></tr><tr><td>数据库</td><td>慢日志、连接数、锁等待、备份状态</td></tr><tr><td>Redis</td><td>内存使用、连接数、慢查询、key 过期策略</td></tr><tr><td>消息队列</td><td>队列积压、消费失败率、重试情况、死信队列</td></tr><tr><td>Kubernetes</td><td>Pod 状态、Events、容器日志、Service 后端、Ingress 规则</td></tr><tr><td>CI/CD</td><td>构建日志、制品版本、发布记录</td></tr><tr><td>缓存</td><td>命中率、内存使用、过期策略</td></tr><tr><td>API 网关</td><td>路由命中、限流触发、认证失败</td></tr><tr><td>应用</td><td>应用日志、指标(/metrics)、链路追踪</td></tr></tbody></table><h3 id="没有排查入口-黑箱" tabindex="-1">没有排查入口 = 黑箱 <a class="header-anchor" href="#没有排查入口-黑箱" aria-label="Permalink to &quot;没有排查入口 = 黑箱&quot;">​</a></h3><p><strong>功能看起来很好,但没有日志、没有指标、没有备份和恢复文档,就很难放到关键链路上</strong>。</p><p>举个反面例子:消息队列接入后,如果看不到:</p><ul><li>队列长度</li><li>消费者在线状态</li><li>失败消息去向</li><li>重试次数</li></ul><p>用户报&quot;任务一直显示进行中&quot;,运维完全无法定位:</p><ul><li>是任务没投递?</li><li>队列积压?</li><li>消费者报错?</li><li>文件上传失败?</li></ul><p><strong>这种系统设计是失败的</strong>——能跑起来但出问题查不动。</p><h3 id="选型时的核对清单" tabindex="-1">选型时的核对清单 <a class="header-anchor" href="#选型时的核对清单" aria-label="Permalink to &quot;选型时的核对清单&quot;">​</a></h3><p>任何组件引入前,确认:</p><ul><li>[ ] 日志输出在哪?如何收集和查询?</li><li>[ ] 关键指标如何采集?能否接入 Prometheus?</li><li>[ ] 健康检查接口?</li><li>[ ] 配置如何管理?</li><li>[ ] 数据如何备份?</li><li>[ ] 数据如何恢复?(真正演练过)</li><li>[ ] 版本升级流程?</li><li>[ ] 出现典型问题时,具体看哪里、用什么命令?</li><li>[ ] 故障演练做过吗?</li></ul><p>任一项答不上来,<strong>这个组件还没准备好进生产</strong>。</p><h2 id="六、退出路径-选型时同样重要" tabindex="-1">六、退出路径:选型时同样重要 <a class="header-anchor" href="#六、退出路径-选型时同样重要" aria-label="Permalink to &quot;六、退出路径:选型时同样重要&quot;">​</a></h2><p>很多人选型只考虑&quot;怎么进去&quot;,不考虑&quot;怎么出来&quot;。但<strong>任何技术选型都应该提前想好退出路径</strong>。</p><h3 id="锁定风险" tabindex="-1">锁定风险 <a class="header-anchor" href="#锁定风险" aria-label="Permalink to &quot;锁定风险&quot;">​</a></h3><table tabindex="0"><thead><tr><th>风险类型</th><th>表现</th></tr></thead><tbody><tr><td>数据格式封闭</td><td>想迁移时发现导不出完整数据,只能靠厂商工具</td></tr><tr><td>API 强绑定</td><td>换平台要大改代码</td></tr><tr><td>配置不可复制</td><td>只能在控制台点点点,无法纳入版本管理</td></tr><tr><td>成本不可控</td><td>流量、存储、API 调用涨上去后费用爆炸</td></tr><tr><td>升级困难</td><td>老版本不兼容新版本,迁移复杂或不存在</td></tr><tr><td>维护方变更</td><td>厂商被收购、项目停止维护</td></tr><tr><td>单一供应商依赖</td><td>厂商涨价或服务质量下降时无议价能力</td></tr></tbody></table><h3 id="完全不锁定是不现实的" tabindex="-1">完全不锁定是不现实的 <a class="header-anchor" href="#完全不锁定是不现实的" aria-label="Permalink to &quot;完全不锁定是不现实的&quot;">​</a></h3><p>云数据库、对象存储、消息服务都会有平台特性。<strong>关键是清楚锁定在哪里</strong>:</p><ul><li>核心数据有导出方式吗?(MySQL binlog 可以拉出来、对象存储文件可批量下载)</li><li>迁移要改哪些代码?</li><li>迁移要改哪些配置?</li><li>迁移期间的并行运行成本多大?</li></ul><p><strong>心里有数的事不算风险,心里没数的事才是真风险</strong>。</p><h3 id="厂商绑定的合理边界" tabindex="-1">厂商绑定的合理边界 <a class="header-anchor" href="#厂商绑定的合理边界" aria-label="Permalink to &quot;厂商绑定的合理边界&quot;">​</a></h3><p>完全的&quot;零厂商绑定&quot;会让架构无法享受云厂商的高级能力。合理的做法:</p><ul><li>数据层:坚持用标准 SQL、标准接口,不用厂商扩展</li><li>中间件:用厂商兼容版本(如阿里云的 Kafka 兼容 RocketMQ)</li><li>应用部署:用 K8s 等标准抽象,而非厂商自有的容器平台</li><li>接受锁定的部分:CDN、对象存储等基础服务,跨家迁移成本可接受</li></ul><h2 id="七、典型组合-内部运维平台的起步选型" tabindex="-1">七、典型组合:内部运维平台的起步选型 <a class="header-anchor" href="#七、典型组合-内部运维平台的起步选型" aria-label="Permalink to &quot;七、典型组合:内部运维平台的起步选型&quot;">​</a></h2><p>如果不知道从哪开始,内部运维平台可以从这样一组<strong>稳定组合</strong>起步:</p><table tabindex="0"><thead><tr><th>层次</th><th>推荐选择</th></tr></thead><tbody><tr><td>前端</td><td>Vue 或 React(国内 Vue 上手更快)</td></tr><tr><td>后端</td><td>Python FastAPI、Go、Java Spring Boot(看团队)</td></tr><tr><td>数据库</td><td>PostgreSQL 或 MySQL</td></tr><tr><td>缓存</td><td>Redis</td></tr><tr><td>文件</td><td>对象存储(OSS/S3)或自建 MinIO</td></tr><tr><td>入口</td><td>Nginx、云负载均衡或 K8s Ingress</td></tr><tr><td>指标</td><td>Prometheus + Grafana</td></tr><tr><td>日志</td><td>Loki、OpenSearch 或 ELK</td></tr><tr><td>发布</td><td>GitLab CI、Jenkins、Argo CD</td></tr><tr><td>容器</td><td>Docker(本地)+ Kubernetes(生产)</td></tr><tr><td>配置</td><td>配置文件 + 环境变量,稍大规模上 Apollo/Nacos</td></tr></tbody></table><h3 id="这张表只是起点" tabindex="-1">这张表只是起点 <a class="header-anchor" href="#这张表只是起点" aria-label="Permalink to &quot;这张表只是起点&quot;">​</a></h3><p>这张表只列出<strong>每层的&quot;位置&quot;</strong>,告诉你大概选什么类型。<strong>真正落地时,每一层都要补上运维问题的答案</strong>:</p><ul><li>数据库怎么备份和恢复?演练过吗?</li><li>Redis 内存满了怎么看?</li><li>对象存储文件怎么迁移?</li><li>入口日志在哪查?</li><li>发布失败怎么回滚?</li><li>监控告警谁负责接听?</li><li>容量规划怎么做?</li><li>版本升级流程?</li></ul><p><strong>这些问题答不上来,选型就没真正完成</strong>——系统上生产只是早晚出事的问题。</p><h2 id="八、选型决策的检查清单" tabindex="-1">八、选型决策的检查清单 <a class="header-anchor" href="#八、选型决策的检查清单" aria-label="Permalink to &quot;八、选型决策的检查清单&quot;">​</a></h2><p>任何技术选型决策前,过一遍这份清单:</p><h3 id="第一组-问题确认" tabindex="-1">第一组:问题确认 <a class="header-anchor" href="#第一组-问题确认" aria-label="Permalink to &quot;第一组:问题确认&quot;">​</a></h3><ul><li>[ ] 真实问题是什么?(具体到指标、错误信息、影响范围)</li><li>[ ] 简单方案能否解决?</li><li>[ ] 引入新组件能带来什么具体收益?</li><li>[ ] 不引入的代价?</li></ul><h3 id="第二组-基础评估" tabindex="-1">第二组:基础评估 <a class="header-anchor" href="#第二组-基础评估" aria-label="Permalink to &quot;第二组:基础评估&quot;">​</a></h3><ul><li>[ ] 组件的核心功能与当前需求匹配吗?</li><li>[ ] 性能指标在合理范围吗?</li><li>[ ] 资源消耗(CPU、内存、磁盘、网络)能接受吗?</li><li>[ ] 与现有技术栈兼容吗?</li></ul><h3 id="第三组-成熟度" tabindex="-1">第三组:成熟度 <a class="header-anchor" href="#第三组-成熟度" aria-label="Permalink to &quot;第三组:成熟度&quot;">​</a></h3><ul><li>[ ] 项目维护活跃吗?最近的 release 是什么时候?</li><li>[ ] 有大规模生产案例吗?</li><li>[ ] 文档完整吗?</li><li>[ ] 社区响应速度如何?</li><li>[ ] 历史安全漏洞响应及时吗?</li></ul><h3 id="第四组-团队能力" tabindex="-1">第四组:团队能力 <a class="header-anchor" href="#第四组-团队能力" aria-label="Permalink to &quot;第四组:团队能力&quot;">​</a></h3><ul><li>[ ] 团队熟悉相关技术吗?</li><li>[ ] 招聘市场上能找到有经验的人吗?</li><li>[ ] 学习成本能接受吗?</li><li>[ ] 紧急情况下谁能介入?</li></ul><h3 id="第五组-运维准备" tabindex="-1">第五组:运维准备 <a class="header-anchor" href="#第五组-运维准备" aria-label="Permalink to &quot;第五组:运维准备&quot;">​</a></h3><ul><li>[ ] 日志、指标、追踪如何接入?</li><li>[ ] 备份和恢复方案?</li><li>[ ] 监控告警规则?</li><li>[ ] 版本升级流程?</li><li>[ ] 应急预案?</li></ul><h3 id="第六组-退出路径" tabindex="-1">第六组:退出路径 <a class="header-anchor" href="#第六组-退出路径" aria-label="Permalink to &quot;第六组:退出路径&quot;">​</a></h3><ul><li>[ ] 数据如何导出?</li><li>[ ] 配置如何迁移?</li><li>[ ] 迁出的工程量评估?</li><li>[ ] 锁定在哪些点?可以接受吗?</li></ul><p>任一组的关键问题答不上来,<strong>继续评估,直到答上为止</strong>——不要在带着不确定的情况下做技术决策。</p><h2 id="九、技术选型是长期决定" tabindex="-1">九、技术选型是长期决定 <a class="header-anchor" href="#九、技术选型是长期决定" aria-label="Permalink to &quot;九、技术选型是长期决定&quot;">​</a></h2><p>技术选型的影响是<strong>长期的</strong>:</p><ul><li>一次错误的数据库选型,影响 3-5 年</li><li>一次错误的语言选型,影响整个团队招聘</li><li>一次错误的微服务拆分,影响后续所有迭代速度</li></ul><p>正因为影响长期,<strong>选型决策要慎重</strong>——值得花充足的时间评估、做 POC、与现有用户交流、参考真实案例。</p><table tabindex="0"><thead><tr><th>时间投入</th><th>决策质量</th></tr></thead><tbody><tr><td>5 分钟看了个 hot 项目就决定</td><td>风险极高</td></tr><tr><td>看了官方文档 + 几个 blog</td><td>不够</td></tr><tr><td>POC 验证关键场景 + 跑通完整链路</td><td>合理</td></tr><tr><td>POC + 邀请有经验的人评审 + 小范围试用</td><td>较稳</td></tr><tr><td>试运行 1-3 个月再正式投产</td><td>最稳</td></tr></tbody></table><p><strong>选错的代价远大于选型耗时</strong>——基础组件的替换成本通常是初次接入的 10 倍以上。</p><h2 id="十、结语-回到工程本质" tabindex="-1">十、结语:回到工程本质 <a class="header-anchor" href="#十、结语-回到工程本质" aria-label="Permalink to &quot;十、结语:回到工程本质&quot;">​</a></h2><p>技术选型最终回到一个简单的问题:<strong>这个技术能否帮助团队稳定、高效地交付业务价值?</strong></p><ul><li>不是哪个技术最先进</li><li>不是哪个技术最流行</li><li>不是哪个技术性能最好</li><li>不是哪个技术名字最酷</li></ul><p>而是:</p><ul><li>团队能否用好?</li><li>出问题能否查?</li><li>数据能否保护?</li><li>长期能否维护?</li><li>退出能否优雅?</li></ul><p>整个&quot;互联网与架构基础&quot;系列从一次网站访问讲起,经过 DNS、HTTP、前后端、数据库、集群、负载均衡、高可用、微服务、容器化、可观测、企业架构、容灾,最终回到选型常识——<strong>回到工程本身</strong>。</p><p>技术服务于业务,不是反过来。理解每一层的位置、每一个组件解决什么问题、每一次演进的代价与收益——比追逐任何&quot;最先进的架构&quot;都重要。</p>',127)])])}const P=d(s,[["render",h]]);export{m as __pageData,P as default};
